select * from ygt_member_benefit_log
where ygt_mbl_join_source_id = #{joinSourceId}
and ygt_mbl_benefit_code = #{benefitCode}
limit 1

select * from ygt_member_benefit_log

    and ygt_mbl_join_source_id = #{joinSourceId}
    and ygt_mbl_customer_user_id = #{customerUserId}

order by ygt_member_benefit_log_id desc
limit #{offset}, #{limit}
